  }

  // --- Step 4: Policy evaluation ---
  let policyResult: ProxyPolicyResult | undefined;
  if (parsed?.model && !isCountTokens) {
    const policyDeps: ProxyPolicyDependencies = {
      surreal: deps.surreal,
      inflight: deps.inflight,
