  1→/**
  2→ * Context Injector -- Pure functions for brain-context injection
  3→ *
  4→ * Responsible for:
  5→ * 1. Ranking context candidates by weighted cosine similarity
  6→ * 2. Selecting top N within token budget
  7→ * 3. Building <brain-context> XML block
  8→ * 4. Injecting into system prompt (string or array form)
  9→ *
 10→ * All functions are pure -- no IO, no side effects.
 11→ * The orchestration (embedding, cache, DB queries) lives in the proxy route.
 12→ */
 13→import { RecordId } from "surrealdb";
 14→import { cosineSimilarity } from "../graph/embeddings";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ContextCandidate = {
 21→  readonly id: string;
 22→  readonly type: "decision" | "learning" | "observation";
 23→  readonly text: string;
 24→  readonly embedding?: number[];
 25→  readonly weight: number;
 26→};
 27→
 28→export type RankedCandidate = {
 29→  readonly id: string;
 30→  readonly type: "decision" | "learning" | "observation";
 31→  readonly text: string;
 32→  readonly score: number;
 33→};
 34→
 35→export type InjectionResult = {
 36→  readonly system: string | Array<{ type: string; text: string; cache_control?: { type: string } }>;
 37→  readonly injected: boolean;
 38→  readonly tokensEstimated: number;
 39→  readonly decisionsCount: number;
 40→  readonly learningsCount: number;
 41→  readonly observationsCount: number;
 42→};
 43→
 44→type SystemPrompt = string | Array<{ type: string; text: string; cache_control?: { type: string } }> | undefined;
 45→
 46→// ---------------------------------------------------------------------------
 47→// Recent Changes Types (04-01: vector search classification)
 48→// ---------------------------------------------------------------------------
 49→
 50→export type RecentChangeCandidate = {
 51→  readonly id: string;
 52→  readonly table: "decision" | "task" | "observation";
 53→  readonly text: string;
 54→  readonly similarity: number;
 55→  readonly updatedAt: string;
 56→};
 57→
 58→export type ClassifiedChange = RecentChangeCandidate & {
 59→  readonly classification: "urgent-context" | "context-update";
 60→};
 61→
 62→// ---------------------------------------------------------------------------
 63→// Token Estimation (pure, ~4 chars per token)
 64→// ---------------------------------------------------------------------------
 65→
 66→export function estimateTokenCount(text: string): number {
 67→  return Math.ceil(text.length / 4);
 68→}
 69→
 70→// ---------------------------------------------------------------------------
 71→// Ranking: weighted cosine similarity
 72→// ---------------------------------------------------------------------------
 73→
 74→export function rankCandidates(
 75→  candidates: ContextCandidate[],
 76→  queryEmbedding: number[],
 77→): RankedCandidate[] {
 78→  return candidates
 79→    .map((c) => {
 80→      const hasEmbedding = c.embedding !== undefined && c.embedding.length > 0;
 81→      const score = hasEmbedding
 82→        ? cosineSimilarity(c.embedding!, queryEmbedding) * c.weight
 83→        : c.weight * 0.5;
 84→      return { id: c.id, type: c.type, text: c.text, score };
 85→    })
 86→    .sort((a, b) => b.score - a.score);
 87→}
 88→
 89→// ---------------------------------------------------------------------------
 90→// Budget Selection: top N within token budget
 91→// ---------------------------------------------------------------------------
 92→
 93→export function selectWithinBudget(
 94→  ranked: RankedCandidate[],
 95→  tokenBudget: number,
 96→): RankedCandidate[] {
 97→  const selected: RankedCandidate[] = [];
 98→  let tokensUsed = 0;
 99→
100→  for (const candidate of ranked) {
101→    const candidateTokens = estimateTokenCount(candidate.text);
102→    if (tokensUsed + candidateTokens > tokenBudget) break;
103→    selected.push(candidate);
104→    tokensUsed += candidateTokens;
105→  }
106→
107→  return selected;
108→}
109→
110→// ---------------------------------------------------------------------------
111→// XML Block Construction
112→// ---------------------------------------------------------------------------
113→
114→export function buildBrainContextXml(selected: RankedCandidate[]): string {
115→  if (selected.length === 0) return "";
116→
117→  const decisions = selected.filter((c) => c.type === "decision");
118→  const learnings = selected.filter((c) => c.type === "learning");
119→  const observations = selected.filter((c) => c.type === "observation");
120→
121→  const sections: string[] = [];
122→
123→  if (decisions.length > 0) {
124→    const items = decisions.map((d) => `  <item>${d.text}</item>`).join("\n");
125→    sections.push(`<decisions>\n${items}\n</decisions>`);
126→  }
127→
128→  if (learnings.length > 0) {
129→    const items = learnings.map((l) => `  <item>${l.text}</item>`).join("\n");
130→    sections.push(`<learnings>\n${items}\n</learnings>`);
131→  }
132→
133→  if (observations.length > 0) {
134→    const items = observations.map((o) => `  <item>${o.text}</item>`).join("\n");
135→    sections.push(`<observations>\n${items}\n</observations>`);
136→  }
137→
138→  return `<brain-context>\n${sections.join("\n")}\n</brain-context>`;
139→}
140→
141→// ---------------------------------------------------------------------------
142→// System Prompt Injection
143→// ---------------------------------------------------------------------------
144→
145→export function injectBrainContext(
146→  originalSystem: SystemPrompt,
147→  brainContextXml: string,
148→): InjectionResult {
149→  if (!brainContextXml) {
150→    return {
151→      system: originalSystem ?? "",
152→      injected: false,
153→      tokensEstimated: 0,
154→      decisionsCount: 0,
155→      learningsCount: 0,
156→      observationsCount: 0,
157→    };
158→  }
159→
160→  const tokensEstimated = estimateTokenCount(brainContextXml);
161→
162→  // Count items in XML (by counting <item> tags per section)
163→  const decisionsCount = (brainContextXml.match(/<decisions>[\s\S]*?<\/decisions>/)?.[0]?.match(/<item>/g) ?? []).length;
164→  const learningsCount = (brainContextXml.match(/<learnings>[\s\S]*?<\/learnings>/)?.[0]?.match(/<item>/g) ?? []).length;
165→  const observationsCount = (brainContextXml.match(/<observations>[\s\S]*?<\/observations>/)?.[0]?.match(/<item>/g) ?? []).length;
166→
167→  if (Array.isArray(originalSystem)) {
168→    // Array-form: append brain-context as additional text block with cache_control: ephemeral
169→    const enriched = [
170→      ...originalSystem,
171→      {
172→        type: "text",
173→        text: brainContextXml,
174→        cache_control: { type: "ephemeral" },
175→      },
176→    ];
177→
178→    return {
179→      system: enriched,
180→      injected: true,
181→      tokensEstimated,
182→      decisionsCount,
183→      learningsCount,
184→      observationsCount,
185→    };
186→  }
187→
188→  if (typeof originalSystem === "string") {
189→    // String-form: append brain-context after original text
190→    return {
191→      system: `${originalSystem}\n\n${brainContextXml}`,
192→      injected: true,
193→      tokensEstimated,
194→      decisionsCount,
195→      learningsCount,
196→      observationsCount,
197→    };
198→  }
199→
200→  // No original system prompt: use brain-context as system prompt
201→  return {
202→    system: brainContextXml,
203→    injected: true,
204→    tokensEstimated,
205→    decisionsCount,
206→    learningsCount,
207→    observationsCount,
208→  };
209→}
210→
211→// ---------------------------------------------------------------------------
212→// Recent Changes Injection into System Prompt (04-02: pure)
213→// ---------------------------------------------------------------------------
214→
215→/**
216→ * Injects recent changes XML into a system prompt with correct ordering:
217→ * - <urgent-context> is injected BEFORE <brain-context>
218→ * - <context-update> is injected AFTER <brain-context>
219→ *
220→ * For array-form system prompts, each block becomes a separate text element
221→ * with cache_control: ephemeral.
222→ */
223→export function injectRecentChanges(
224→  system: SystemPrompt,
225→  recentChangesXml: string,
226→): InjectionResult["system"] {
227→  if (!recentChangesXml) return system ?? "";
228→
229→  // Extract urgent-context and context-update blocks from the XML
230→  const urgentMatch = recentChangesXml.match(/<urgent-context>[\s\S]*?<\/urgent-context>/);
231→  const updateMatch = recentChangesXml.match(/<context-update>[\s\S]*?<\/context-update>/);
232→
233→  const urgentBlock = urgentMatch?.[0] ?? "";
234→  const updateBlock = updateMatch?.[0] ?? "";
235→
236→  if (!urgentBlock && !updateBlock) return system ?? "";
237→
238→  if (Array.isArray(system)) {
239→    const result = [...system];
240→
241→    // Find the brain-context block index for insertion ordering
242→    const brainContextIdx = result.findIndex(
243→      (block) => typeof block.text === "string" && block.text.includes("<brain-context>"),
244→    );
245→
246→    if (brainContextIdx >= 0) {
247→      // Insert urgent BEFORE brain-context, update AFTER
248→      if (updateBlock) {
249→        result.splice(brainContextIdx + 1, 0, {
250→          type: "text",
251→          text: updateBlock,
252→          cache_control: { type: "ephemeral" },
253→        });
254→      }
255→      if (urgentBlock) {
256→        result.splice(brainContextIdx, 0, {
257→          type: "text",
258→          text: urgentBlock,
259→          cache_control: { type: "ephemeral" },
260→        });
261→      }
262→    } else {
263→      // No brain-context block -- append both at end (urgent first, then update)
264→      if (urgentBlock) {
265→        result.push({ type: "text", text: urgentBlock, cache_control: { type: "ephemeral" } });
266→      }
267→      if (updateBlock) {
268→        result.push({ type: "text", text: updateBlock, cache_control: { type: "ephemeral" } });
269→      }
270→    }
271→
272→    return result;
273→  }
274→
275→  if (typeof system === "string") {
276→    // String-form: find <brain-context> position for ordering
277→    const brainContextPos = system.indexOf("<brain-context>");
278→
279→    if (brainContextPos >= 0) {
280→      const brainContextEnd = system.indexOf("</brain-context>");
281→      const afterBrainContext = brainContextEnd >= 0
282→        ? brainContextEnd + "</brain-context>".length
283→        : system.length;
284→
285→      const before = system.slice(0, brainContextPos);
286→      const brainSection = system.slice(brainContextPos, afterBrainContext);
287→      const after = system.slice(afterBrainContext);
288→
289→      const parts = [before.trimEnd()];
290→      if (urgentBlock) parts.push(urgentBlock);
291→      parts.push(brainSection);
292→      if (updateBlock) parts.push(updateBlock);
293→      parts.push(after.trimStart());
294→
295→      return parts.filter(Boolean).join("\n\n");
296→    }
297→
298→    // No brain-context -- append both
299→    const parts = [system];
300→    if (urgentBlock) parts.push(urgentBlock);
301→    if (updateBlock) parts.push(updateBlock);
302→    return parts.join("\n\n");
303→  }
304→
305→  // No existing system prompt -- combine blocks
306→  const parts: string[] = [];
307→  if (urgentBlock) parts.push(urgentBlock);
308→  if (updateBlock) parts.push(updateBlock);
309→  return parts.join("\n\n");
310→}
311→
312→// ---------------------------------------------------------------------------
313→// Recent Changes Classification (04-01: pure)
314→// ---------------------------------------------------------------------------
315→
316→const URGENT_CONTEXT_THRESHOLD = 0.85;
317→const CONTEXT_UPDATE_THRESHOLD = 0.65;
318→
319→/**
320→ * Classifies KNN search results by similarity into urgent-context or context-update.
321→ *
322→ * - >= 0.85 similarity -> urgent-context (agent should act on this immediately)
323→ * - >= 0.65 similarity -> context-update (background awareness)
324→ * - < 0.65 similarity  -> filtered out (not relevant)
325→ *
326→ * Preserves input order for candidates that pass the threshold.
327→ */
328→export function classifyBySimilarity(
329→  candidates: RecentChangeCandidate[],
330→): ClassifiedChange[] {
331→  return candidates
332→    .filter((c) => c.similarity >= CONTEXT_UPDATE_THRESHOLD)
333→    .map((c) => ({
334→      ...c,
335→      classification: c.similarity >= URGENT_CONTEXT_THRESHOLD
336→        ? "urgent-context" as const
337→        : "context-update" as const,
338→    }));
339→}
340→
341→// ---------------------------------------------------------------------------
342→// Recent Changes XML Builder (04-01: pure)
343→// ---------------------------------------------------------------------------
344→
345→/**
346→ * Builds an XML block for recent graph changes classified by urgency.
347→ *
348→ * Output structure:
349→ * <recent-changes>
350→ *   <urgent-context>
351→ *     <item type="decision">Use tRPC for all APIs</item>
352→ *   </urgent-context>
353→ *   <context-update>
354→ *     <item type="task">Implement rate limiting</item>
355→ *   </context-update>
356→ * </recent-changes>
357→ */
358→function escapeXml(text: string): string {
359→  return text
360→    .replace(/&/g, "&amp;")
361→    .replace(/</g, "&lt;")
362→    .replace(/>/g, "&gt;")
363→    .replace(/"/g, "&quot;");
364→}
365→
366→export function buildRecentChangesXml(changes: ClassifiedChange[]): string {
367→  if (changes.length === 0) return "";
368→
369→  const urgent = changes.filter((c) => c.classification === "urgent-context");
370→  const updates = changes.filter((c) => c.classification === "context-update");
371→
372→  const sections: string[] = [];
373→
374→  if (urgent.length > 0) {
375→    const items = urgent
376→      .map((c) => `  <item type="${escapeXml(c.table)}">${escapeXml(c.text)}</item>`)
377→      .join("\n");
378→    sections.push(`<urgent-context>\n${items}\n</urgent-context>`);
379→  }
380→
381→  if (updates.length > 0) {
382→    const items = updates
383→      .map((c) => `  <item type="${escapeXml(c.table)}">${escapeXml(c.text)}</item>`)
384→      .join("\n");
385→    sections.push(`<context-update>\n${items}\n</context-update>`);
386→  }
387→
388→  return `<recent-changes>\n${sections.join("\n")}\n</recent-changes>`;
389→}
390→
391→// ---------------------------------------------------------------------------
392→// Recent Changes Vector Search (04-01: adapter boundary -- DB side effect)
393→// ---------------------------------------------------------------------------
394→
395→/**
396→ * Port signature for searching recent graph changes by vector similarity.
397→ */
398→export type SearchRecentChanges = (
399→  messageEmbedding: number[],
400→  workspaceId: string,
401→  lastRequestAt: Date,
402→) => Promise<RecentChangeCandidate[]>;
403→
404→type KnnRow = {
405→  id: RecordId;
406→  text: string;
407→  similarity: number;
408→  updated_at: string;
409→  workspace: RecordId;
410→};
411→
412→/**
413→ * Searches for recent graph entity changes relevant to a message embedding.
414→ *
415→ * Uses the two-step KNN pattern required by SurrealDB v3.0 (see CLAUDE.md):
416→ * - Step 1: KNN candidates via HNSW index (no WHERE filter)
417→ * - Step 2: filter by workspace + updated_at > last_request_at
418→ *
419→ * Queries decision, task, and observation tables independently then merges results.
420→ */
421→export function createSearchRecentChanges(
422→  surreal: { query: <T>(sql: string, vars?: Record<string, unknown>) => Promise<T> },
423→): SearchRecentChanges {
424→  return async (
425→    messageEmbedding: number[],
426→    workspaceId: string,
427→    lastRequestAt: Date,
428→  ): Promise<RecentChangeCandidate[]> => {
429→    const workspaceRecord = new RecordId("workspace", workspaceId);
430→    const knnLimit = 20;
431→
432→    // Two-step KNN pattern for each table (HNSW index cannot combine with B-tree WHERE)
433→    // Sequential queries to avoid SurrealDB SDK WebSocket concurrency issues
434→    const decisionResults = await surreal.query<[KnnRow[], KnnRow[]]>(
435→      `LET $candidates = SELECT id, summary AS text, vector::similarity::cosine(embedding, $vec) AS similarity, updated_at, workspace
436→         FROM decision WHERE embedding <|${knnLimit}, COSINE|> $vec;
437→       SELECT * FROM $candidates WHERE workspace = $ws AND updated_at > $since ORDER BY similarity DESC LIMIT $limit;`,
438→      { vec: messageEmbedding, ws: workspaceRecord, since: lastRequestAt, limit: knnLimit },
439→    );
440→
441→    const taskResults = await surreal.query<[KnnRow[], KnnRow[]]>(
442→      `LET $candidates = SELECT id, title AS text, vector::similarity::cosine(embedding, $vec) AS similarity, updated_at, workspace
443→         FROM task WHERE embedding <|${knnLimit}, COSINE|> $vec;
444→       SELECT * FROM $candidates WHERE workspace = $ws AND updated_at > $since ORDER BY similarity DESC LIMIT $limit;`,
445→      { vec: messageEmbedding, ws: workspaceRecord, since: lastRequestAt, limit: knnLimit },
446→    );
447→
448→    const observationResults = await surreal.query<[KnnRow[], KnnRow[]]>(
449→      `LET $candidates = SELECT id, text, vector::similarity::cosine(embedding, $vec) AS similarity, updated_at, workspace
450→         FROM observation WHERE embedding <|${knnLimit}, COSINE|> $vec;
451→       SELECT * FROM $candidates WHERE workspace = $ws AND updated_at > $since ORDER BY similarity DESC LIMIT $limit;`,
452→      { vec: messageEmbedding, ws: workspaceRecord, since: lastRequestAt, limit: knnLimit },
453→    );
454→
455→    function toRecentChangeCandidates(
456→      rows: KnnRow[],
457→      table: RecentChangeCandidate["table"],
458→    ): RecentChangeCandidate[] {
459→      return rows.map((row) => ({
460→        id: (row.id as RecordId).id as string,
461→        table,
462→        text: row.text,
463→        similarity: row.similarity,
464→        updatedAt: row.updated_at,
465→      }));
466→    }
467→
468→    return [
469→      ...toRecentChangeCandidates(decisionResults[1] ?? [], "decision"),
470→      ...toRecentChangeCandidates(taskResults[1] ?? [], "task"),
471→      ...toRecentChangeCandidates(observationResults[1] ?? [], "observation"),
472→    ];
473→  };
474→}
